INSERT INTO "Category" ("id", "name", "name_en", "description", "description_en") VALUES
(1, '动植物及检疫物（470号公告）', 'Animals, Plants, and Quarantine Objects (Announcement No. 470)', '中华人民共和国禁止携带、寄递进境的动植物及其产品和其他检疫物名录。', 'List of animals, plants, products, and other quarantine objects prohibited from being carried or posted into the People''s Republic of China.'),
(2, '禁止进境物品', 'Generally Prohibited Imports', '根据中华人民共和国海关法规定，禁止进境的物品。', 'Items prohibited from import according to the Customs Law of the People''s Republic of China.'),
(3, '限制进境物品', 'Generally Restricted Imports', '根据中华人民共和国海关法规定，限制进境的物品。', 'Items restricted from import according to the Customs Law of the People''s Republic of China.');
INSERT INTO "Item" ("name", "name_en", "description", "description_en", "status", "restrictions", "restrictions_en", "category_id", "source", "last_updated") VALUES
('活动物', 'Live Animals', '包括所有的哺乳动物、鸟类、鱼类、甲壳类、两栖类、爬行类、昆虫类和其他无脊椎动物，动物遗传物质。', 'Including all mammals, birds, fish, crustaceans, amphibians, reptiles, insects, and other invertebrates, and animal genetic material.', 'Prohibited', '犬、猫除外', 'Except for dogs and cats', 1, '470号公告', NULL),
('（生或熟）肉类及其制品', '(Raw or Cooked) Meat and Products', '含脏器类。', 'Including offal/organs.', 'Prohibited', '无', 'None', 1, '470号公告', NULL),
('水生动物产品', 'Aquatic Animal Products', '无', 'None', 'Prohibited', '干制、熟制、发酵后制成的食用酱汁水生动物产品除外。', 'Except for aquatic animal products processed into edible sauces (dried, cooked, or fermented).', 1, '470号公告', NULL),
('动物源性乳及乳制品', 'Animal-derived Milk and Dairy Products', '包括生乳、巴氏杀菌乳、灭菌乳、调制乳、发酵乳，奶油、黄油奶酪、炼乳等乳制品。', 'Including raw milk, pasteurized milk, sterilized milk, formulated milk, fermented milk, cream, butter, cheese, condensed milk, and other dairy products.', 'Prohibited', '无', 'None', 1, '470号公告', NULL),
('蛋及其制品', 'Eggs and Egg Products', '包括鲜蛋皮蛋、咸蛋、蛋液、蛋壳、蛋黄酱等蛋源产品。', 'Including fresh eggs, preserved eggs, salted eggs, liquid egg, eggshells, mayonnaise, and other egg source products.', 'Prohibited', '无', 'None', 1, '470号公告', NULL),
('燕窝', 'Edible Bird''s Nests', '无', 'None', 'Prohibited', '经商业无菌处理的罐头装燕窝除外。', 'Except for canned edible bird''s nests that have undergone commercial sterilization.', 1, '470号公告', NULL),
('油脂类、皮张、毛类、蹄（爪）骨、牙、角类及其制品', 'Fats, Hides, Hair, Hoof/Claw/Bone, Teeth, Horns and their Products', '无', 'None', 'Prohibited', '经加工处理且无血污、肌肉和脂肪等的蛋壳类、蹄（爪）骨角类、甲壳类等工艺品除外。', 'Except for handicrafts made from eggshells, hooves, claws, bones, horns, crustaceans, etc., that have been processed and are free of blood stains, muscle, and fat.', 1, '470号公告', NULL),
('动物源性饲料、中药材、肥料', 'Animal-derived Feed, Chinese Herbal Medicine, and Fertilizer', '动物源性。', 'Animal-derived.', 'Prohibited', '无', 'None', 1, '470号公告', NULL),
